mapper.select:
SELECT , best.best_rank_value FROM university u LEFT JOIN ( SELECT re.university_id, MIN(re.rank_value) AS best_rank_value FROM ranking_entry re WHERE re.deleted = 0 AND re.subject_id IS NULL AND re.rank_value IS NOT NULL AND re.rank_value < 9999 AND re.source_id IN (4, 11, 16, 19, 46, 54) GROUP BY re.university_id ) best ON u.url_id = best.university_id WHERE u.deleted = 0
AND ( u.url_id = #{keyword} OR u.name_zh LIKE CONCAT('%', #{keyword}, '%') OR u.name_en LIKE CONCAT('%', #{keyword}, '%') )
AND u.country = #{country}
AND ( u.country = #{continent}
OR u.country IN
#{c}
)
ORDER BY u.name_en ASC
ORDER BY CASE WHEN best.best_rank_value IS NULL THEN 1 ELSE 0 END ASC, best.best_rank_value ASC, u.name_en ASC

SELECT DISTINCT u.country FROM university u WHERE u.deleted = 0 AND u.country IS NOT NULL AND u.country != '' AND u.country != 'unknown' AND u.country NOT IN ('亚洲', '欧洲', '北美洲', '非洲', '南美洲', '大洋洲', '综合类', '师范类', '理工类', '政法类', '艺术类', '医药类', '财经类', '体育类', '农林类', '民族类', '语言类', '军事类') AND u.country NOT REGEXP '^(山东|山西|江苏|河南|新疆|河北|湖北|湖南|广东|广西|海南|四川|贵州|云南|西藏|陕西|甘肃|青海|辽宁|吉林|黑龙江|内蒙古|宁夏|北京|天津|上海|重庆|香港|澳门|台湾)$'
AND ( u.country = #{continent}
OR u.country IN
#{c}
)
ORDER BY u.country ASC
